window.__QUIZ_DATA__=[{"id":"objective>Mathematics>1998>1","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If S \u2282 R, then","images":[],"options":{"A":"S \u2229 R = R","B":"S \u2229 R = S","C":"S \u22c3 R = S","D":"S \u2229 R = S1"},"answer":"B","explanation":"S \u2282 R means S is a subset of R; by implication it means all the elements in S are contained in R. But the intersection of a set and its subset is the subset to that set: S \u2229 R = S","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>2","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Convert 35 to a number in base two.","images":[],"options":{"A":"1011two","B":"10011two","C":"100011two","D":"110010two"},"answer":"C","explanation":"Therefore, 35 to a number in base two is 100011","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1998>3","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The nth term of a sequence is represented by 3 x 2(2 - n). Write down the first three terms of the sequence.","images":[],"options":{"A":"3/2, 3, 6","B":"6, 3, 3/2","C":"3/2, 3, 1/3","D":"2/3, 3, 8/3"},"answer":"B","explanation":"Tn = 3 x 2(2 - n) \u2234T1 = 3 x 22 - 1 = 3 x 21 = 6    T2 = 3 x 22 - 2 = 3 x 20 = 3 (Recall ao = 1)    T3 = 3 x 22 - 3 = 3 x 2-1 = 3 x 1/2 =  3/2 (Recall a-1 = 1/a)    \u2234 The first three terms are 6, 3, 3/2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>4","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify (14)-11/2","images":[],"options":{"A":"8","B":"4","C":"1/4","D":"3/8"},"answer":"A","explanation":"(14)-11/2 = (4-1)-3/2 = 43/2 = (22)3/2 = 23 = 8","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1998>5","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Find the number whose logarithm to base 10 is 2.6025.","images":[],"options":{"A":"0.0004","B":"4.004","C":"40.04","D":"400.4"},"answer":"D","explanation":"The logarithm of a number to base 10 is 2.6025;  If the number is x; \u2234 log10x = 2.6025  If logax = u \u2234 au = x (law of logarithm)  \u2234 102.6025 = x \u2234 x = 400.4","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>6","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGE ERROR","question":"A piece of cloth was measured as 6.10 m. If the actual length of the cloth is 6.35 m, find the percentage error correct to 2 decimal places.","images":[],"options":{"A":"3.05%","B":"3.94%","C":"15.00%","D":"25.00%"},"answer":"B","explanation":"Actual length = 6.35 m; Measurement = 6.10m  Error = 6.35 m - 6.10 m = 0.25 m  %error=ErrorActual lengthx100%=0.256.35x100%=3.94%","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1998>7","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Simplify82/3 x 27-1/3641/3","images":[],"options":{"A":"-3","B":"1/9","C":"1/3","D":"27/8"},"answer":"C","explanation":"82/3 x 27-1/3641/3 = (3\u221a8)2 x (3\u221a27)-1(3\u221a64)1 = 22 x 3-141 = 4 x 1/34 4/34 =  1/3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>8","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve the equation 5x2 - 4x - 1 = 0","images":[],"options":{"A":"-1, 1/5","B":"-1, -1/5","C":"1, 1/5","D":"1, -1/5"},"answer":"D","explanation":"5x2  - 4x - 1 = 0  ==> 5x2  - 5x + x - 1 = 0   5x(x - 1) + 1(x - 1) = 0  (x - 1)(5x + 1) = 0  x - 1 = 0 or 5x + 1 = 0  x = 1 or 5x = -1  x = 1 or x = -1/5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>9","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : INEQUALITIES","question":"p and q are two positive numbers such that p > 2q. Which one of the following statements is not true?","images":[],"options":{"A":"-p","B":"-p > -2q","C":"-q","D":"q 1/2p"},"answer":"B","explanation":"p > 2q; the sense of an inequality changes when both sides are multiplied by a negative number.  \u2234 -p  -2q (is false)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>10","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : FUNCTIONS AND RELATIONS","question":"For what values of x is the expression x - 5x2 - 2x - 3 not defined?","images":[],"options":{"A":"3, 1","B":"-1, -3","C":"-1, 3","D":"3, -2"},"answer":"C","explanation":"An expression in fraction form is not defined when the denominator equals zero  \u2234 x - 5x2 - 2x - 3 is not defined when x2 - 2x - 3 = 0  \u2234 x2 - 2x - 3 = 0 ==> (x - 3)(x + 1) = 0    x - 3 = 0 or x + 1 = 0    x = 3 or -1","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>11","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Make S the subject of the formula: V = K\u221a(T - S)","images":[],"options":{"A":"S = T - K2V2","B":"S = K2V2 - T","C":"S = T - V2K2","D":"S = T(V2 - K2)V2"},"answer":"A","explanation":"V = K\u221a(T - S) By squaring; V2 = K2(T - S)  \u2234(T-S)V2=K2;T-S=K2V2; S = T - K2V2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>12","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Find the equation whose roots are -2/3 and -1/4?","images":[],"options":{"A":"12x2 + 11x + 2 = 0","B":"12x2 - 11x + 2 = 0","C":"x2 + 11/12x + 2 = 0","D":"x2 + 11/12x - 2 = 0"},"answer":"A","explanation":"Roots are -2/3 and -1/4    Sumofroots=-23+ (-14) =-8 - 312=-1112  Productofroots=-23x (-14) =16  \u2234 Equation whose roots are given above is x2 - (sum of roots)x + products of roots = 0    i.e x2 - (-11/12)x + 1/6 = 0 ==> x2 + 11/12x + 1/6 = 0    \u2234 12x2 + 11x + 2 = 0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>13","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Find (x - y) if 4x - 3y = 7 and 3x - 2y = 5","images":[],"options":{"A":"4","B":"3","C":"2","D":"-2"},"answer":"C","explanation":"4x - 3y = 7 ---- (i)  3x - 2y = 5 ----(ii)  Multiply eq. (i) by (3) and equ. (ii) by (4) then substract  12x - 9y = 21  12x - 8y = 20  (substract)  -y = 1 ==> y = -1  substitute (-1) for y in eq. (ii)  3x - 2(-1) = 5  3x + 2 = 5  3x = 5 - 2  3x = 3  x = 1  \u2234 (x - y) = [1 - (-1)] = 1 + 1 = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>14","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve the inequality (y - 3) y/3","images":[],"options":{"A":"y > -9","B":"y","C":"y > 4","D":"y"},"answer":"D","explanation":"(y - 3) y/3  Multiply through by 3  3(y - 3)  3y - 9  3y - y = 9   2y  \u2234 y 9/2  The only statement that is true is y","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>15","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"if h(m + n) = m(h + r), find h in terms of m, n and r.","images":[],"options":{"A":"h = mr-2m + n","B":"h = mrn - m","C":"h = m + rn","D":"h = mrn"},"answer":"D","explanation":"h(m + n) = m(h + r)  Open the bracket  hm + hn = mh + mr  hm + hn - hm = mr  hn = mr  h=mrn","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>16","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Given that 6x - yx + 2y = 2, find the value of xy","images":[],"options":{"A":"38","B":"58","C":"45","D":"54"},"answer":"D","explanation":"6x - yx + 2y = 21 ==> 1(6x - y) = 2(x + 2y)  6x-y=2x+4y;6x-2x=4y+y;4x=5y;xy=54","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>17","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : LONGITUDES AND LATITUDES","question":"The radius of geographical globe is 60 cm. Find the length of the parallel of latitude 60oN.","images":[],"options":{"A":"66\u03c0 cm","B":"60\u03c0 cm","C":"30\u03c0 cm","D":"15\u03c0 cm"},"answer":"B","explanation":"Radius of geographical globe = 60 cm  Length of parallel of latitude 60oN = 2\u03c0r  = 2\u03c0Rcos 60o = 2\u03c0 x 60 cm x 1/2 = 60\u03c0 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>18","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"In the diagram below, O is the centre of the two concentric circles of radii 13 cm and 10 cm respectively. Find the area of the shaded portion in the sector with an angle of 120o at the centre.","images":["data:image/png;base64,"],"options":{"A":"1/3\u03c0 cm2","B":"\u03c0 cm2","C":"3\u03c0 cm2","D":"23\u03c0 cm2"},"answer":"D","explanation":"Areaoftheshadedportion=Areaofbiggersector-Areaofsmallersector  Areaofasector=\u03b8360x\u03c0r2  Areaoftheshadedportion=120360x\u03c0x132-120360x\u03c0x102=120360x\u03c0(132-102)  Areaoftheshadedportion=13\u03c0(169-100)=13\u03c0(69)=23\u03c0cm2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>19","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Express as a single fraction xx - 2 - x + 2x + 3","images":[],"options":{"A":"2x2 - 3x - 4(x - 2)(x - 3)","B":"2x2 - 3x - 4(x - 2)(x + 3)","C":"2(x - 2)(x + 3)","D":"3x + 4(x - 2)(x + 3)"},"answer":"D","explanation":"xx - 2 - x + 2x + 3 = x(x + 3) - (x - 2)(x + 2)(x - 2)(x + 3) = x2 + 3x - (x2 - 4)(x - 2)(x + 3)  = x2 + 3x - x2 + 4(x - 2)(x + 3) = 3x + 4(x - 2)(x + 3)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>20","subject":"Mathematics","year":"1998","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The following number represents a set of scores for a class of 32 students, where the maximum score possible was 12:  6, 5, 9, 4, 4, 8, 7, 5, 6, 3, 2, 5, 4, 6, 9, 10, 4, 3, 2, 3, 4, 6, 8, 7, 4, 2, 1, 8, 7, 7, 6, 11.  What percentage of the class, correct to the nearest whole number, scored above 6?","images":[],"options":{"A":"34%","B":"35%","C":"37%","D":"38%"},"answer":"A","explanation":"Totalnumberofstudents=32  Noofstudentsthatscoredabove6marks=11  Percentageofstudentsthatscoredabove6marks=1132x100%  =34%(tothenearestwholenumber)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>21","subject":"Mathematics","year":"1998","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A die with faces 1 to 6 is rolled once. What is the probability of obtaining 3 or 4?","images":[],"options":{"A":"1/36","B":"1/6","C":"1/3","D":"1/2"},"answer":"C","explanation":"Probabilityofobtaining3or4=Probabilityofobtaining3+Probabilityofobtaining4  Pr(3)=16  Pr(4)=16  Pr(3or4)=16+16=13","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1998>22","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"In the diagram, the area of triangle ABC is 35 cm2. Find the value of y?","images":["data:image/png;base64,"],"options":{"A":"5 cm","B":"10 cm","C":"17.5 cm","D":"28 cm"},"answer":"B","explanation":"Area of triangle ABC = 35 cm2; Area of triangle = 1/2bh  where b = base ==> BC = y; 1/2y x 7 = 35  = 7/2y = 35  \u2234 y = 10 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>23","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Use the graph below to answer Question below      The graph is that of the quadratic expression:","images":["data:image/png;base64,"],"options":{"A":"y = x2 + x - 2","B":"y = x2 - x + 2","C":"y = x2 - x - 2","D":"y = x2 + x + 2"},"answer":"C","explanation":"The roots from the graph are -1 and 2  \u2234 y = (x - (-1))(x - 2)  ==> y = (x + 1)(x - 2)  \u2234 y = x2 - x - 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>24","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Use the graph below to answer Question below    The values of x when y = -1, are approximately:","images":["data:image/png;base64,"],"options":{"A":"-1.0 and 2.0","B":"-1.3 and 2.3","C":"-0.6 and 2.6","D":"-0.6 and 1.6"},"answer":"D","explanation":"The values of x when y = -1 from the graph are -0.6 and 1.6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>25","subject":"Mathematics","year":"1998","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A box contains 2 white and 3 blue identical balls, if two balls are picked at random, one after the other, without replacement, what is the probability of picking two balls of different colours?","images":[],"options":{"A":"6/25","B":"7/20","C":"3/5","D":"2/3"},"answer":"C","explanation":"Probabilityofpickingtwoballsofdifferentcolours = Pr(white and blue) or Pr(blue and white)  Pr(whiteandblue)=25x34=620=310  Pr(blueandwhite)=35x24=620=310  \u2234 Probabilityofpickingtwoballsofdifferentcolours=310+310=35","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>26","subject":"Mathematics","year":"1998","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"In \u2206PQR, \u2220PRQ is a right angle, |QR| = 2cm and \u2220PRQ = 60o. Find |PR|","images":["data:image/png;base64,"],"options":{"A":"4\u221a3 cm","B":"4 cm","C":"2\u221a3 cm","D":"4/3 cm"},"answer":"B","explanation":"From\u2206PQR;cos60o=AdjacentHypotenuse; cos60o=QRPR  ==>cos60o=2PR; 12=2PR\u2234PR=4cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>27","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, PQ||SR. Find the value of z?","images":["data:image/png;base64,"],"options":{"A":"30o","B":"40o","C":"45o","D":"90o"},"answer":"D","explanation":"Since PQ||SR. If RQ is produced to point T  \u2234 \u2220TQP = \u2220QRS = 2yo (corresponding angles)  \u2234 2yo + \u2220PQR = 180o (angle on a straight line)  2y + 2x = 180o \u2234 x + y = 90o  But x + y + z = 180o (sum of angles in a triangle)  \u2234 90 + z = 180o ==> z = 90o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>28","subject":"Mathematics","year":"1998","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If sin (x + 30)o = cos 40o, find x?","images":[],"options":{"A":"10o","B":"20o","C":"50o","D":"60o"},"answer":"B","explanation":"sin (x + 30)o = cos 40o  From cos \u03b8 = sin (90 - \u03b8) i.e cos 40o = sin (90o - 40o)  \u2234 sin (x + 30)o = sin (90o - 40o)  sin (x + 30)o = sin 50o  sin (x + 30)o = sin (20o + 30o)  By comparing,  x = 20o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>29","subject":"Mathematics","year":"1998","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Find the value of x if cos x = 5/8 for 0 \u2264 x \u2264 180o?","images":[],"options":{"A":"141.3o","B":"128.7o","C":"51.3o","D":"48.7o"},"answer":"C","explanation":"cos x = 5/8    x = cos-1 (5/8)    \u2234 x = 51.3o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>30","subject":"Mathematics","year":"1998","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A ladder 5 m long rests against a wall such that its foot makes an angle of 30o with the horizontal. How far is the foot of the ladder from the wall?","images":[],"options":{"A":"5/3\u221a2 m","B":"21/2 m","C":"5/2\u221a3 m","D":"10/3\u221a3 m"},"answer":"C","explanation":"From the sketch, cos 30o = x/5    \u2234 x = 5cos 30o = 5 x \u221a3/2 = 5/2\u221a3 m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>31","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A chord of a circle of radius 26 cm is 10 cm from the centre of the circle. Calculate the length of the chord?","images":[],"options":{"A":"16 cm","B":"27.86 cm","C":"32 cm","D":"48 cm"},"answer":"D","explanation":"Length of chord = 2x (Line from the centre meeting the chord at right angle bisects the chord)  From \u2206AOC  262 = 102 + x2  676 = 100 + x2  x2 = 676 - 100  x2 = 576  x = 24 cm  \u2234 Length of chord = 2 x 24 cm = 48 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>32","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Two chords PQ and RS of a circle intersect at right angles at a point inside the circle, if \u2220QPR = 35o. Find \u2220PQS?","images":[],"options":{"A":"35o","B":"45o","C":"55o","D":"70o"},"answer":"C","explanation":"From \u2206PRT  35o + 90o + \u2220PRT = 180o (sum of angles in a triangle)  125o + \u2220PRT = 180o  \u2220PRT = 180o - 125o = 55o  \u2220PRT = \u2220PQS (angles in the same segment are equal)  \u2234 \u2220PQS = 55o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>33","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle and reflex angle ROS is 264o. Find \u2220RTS?","images":["data:image/png;base64,"],"options":{"A":"48o","B":"53o","C":"66o","D":"132o"},"answer":"A","explanation":"From the diagram \u2220ROS + 264o = 360o (angles at a point)    \u2220ROS = 360o - 264o = 96o    But \u2220RTS = 1/2(\u2220ROS) (angle at the centre is twice the angle subtends at the circumference)    \u2234 \u2220RTS = 1/2 x 96o = 48o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>34","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"If the exterior angles of quadrilateral are yo, (y + 5)o, (y + 10)o and (y + 25)o, find y?","images":[],"options":{"A":"10o","B":"20o","C":"40o","D":"80o"},"answer":"D","explanation":"The sum of the exterior angles of a quadrilateral (polygon) = 360o  \u2234 yo + (y + 5)o + (y + 10)o + (y + 25)o = 360o  4y + 40o = 360o  4y = 360o - 40o = 320o  \u2234y=320o4=80o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>35","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram PQ is a diameter of circle PMQN, centre O. If \u2220PQM = 63o, find \u2220MNQ?","images":["data:image/png;base64,"],"options":{"A":"58.5o","B":"44o","C":"35o","D":"27o"},"answer":"D","explanation":"From \u2206QPM  \u2220QMP = 90o (the angle in a semi circle is a right angle)  \u2220QPM + 63o + 90o = 180o (sum of angles in a triangle)  \u2220QPM + 153o = 180o  \u2220QPM = 180o - 153o = 27o  \u2220QPM = \u2220MNQ (angles in the same segment are equal)  \u2234 \u2220MNQ = 27o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>36","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram O is the centre of circle PRQ. The radius is 3.5 cm and \u2220POQ = 50o.  Use the diagram to answer Questions below.    [Take \u03c0 = 22/7]    Calculate, correct to one decimal place, the length of arc PQ?","images":["data:image/png;base64,"],"options":{"A":"175.0 cm","B":"157.1 cm","C":"37.7 cm","D":"3.1 cm"},"answer":"D","explanation":"LengthofarcPQ=\u03b8360x2\u03c0r;where\u03b8=50o,r=3.5cm=72cm  \u2234l=50360x2x227x72=5518=3.05cmor3.1cm(to1d.p)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>37","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram O is the centre of circle PRQ. The radius is 3.5 cm and \u2220POQ = 50o.  Use the diagram to answer Questions below.    [Take \u03c0 = 22/7]  Calculate, correct to three significant figures, the area of sector OPQ?","images":["data:image/png;base64,"],"options":{"A":"3.403 cm2","B":"5.35 cm2","C":"10.99 cm2","D":"157.1 cm2"},"answer":"B","explanation":"Areaofsector=\u03b8360x\u03c0r2=50360x227x72x72=5.35cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>38","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"Calculate the area of the trapezium PQRS?","images":["data:image/png;base64,"],"options":{"A":"24 cm","B":"36 cm","C":"44 cm","D":"72 cm"},"answer":"C","explanation":"Perimeter = distance round the object  Since the shape is trapezium and PT||QR  sin \u03b8 = 4/5  Using Pythagoras theorem  \u2234 ST2 = SP2 - PT2  = 52 - 42 = 25 - 16  ST2 = 9  ST = 3 cm  But SR = ST + TR also TR = PQ  \u2234 TR = 16 cm  \u2234 Perimeter = PQ + PS + ST + TR + RQ  = 16 + 5 + 3 + 16 + 4 = 44 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>39","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"The length of an arc of a circle of radius 5 cm is 4 cm. Find the area of the sector?","images":[],"options":{"A":"13/5 cm2","B":"2 cm2","C":"8 cm2","D":"10 cm2"},"answer":"D","explanation":"Lengthofarc=\u03b8360x2\u03c0r   \u22344=\u03b8360x2x227x5  41=220\u03b8360 x 7\u22344x36x7=22\u03b8  \u03b8=4 x 36 x 722=100822=45.81o  Areaofsector=\u03b8360x\u03c0r2  =45.81360x227x5x5=25199.992520=9.9999cm2=10cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>40","subject":"Mathematics","year":"1998","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart shows the distribution of how students travelled to a certain school on a particular day.  Use this information to answer Questions below    If a hundred students travelled by bus. Find the total number of students in the school?","images":["data:image/png;base64,"],"options":{"A":"300","B":"400","C":"500","D":"600"},"answer":"B","explanation":"AnglerepresentingstudentsthattravelledbyBus=90o  PercentageofstudentstravellingbyBus=90360x100%=25%  Iftotalnumberisx  \u223425%ofx=100==>25x100=100\u2234x=400","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>41","subject":"Mathematics","year":"1998","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart shows the distribution of how students travelled to a certain school on a particular day.  Use this information to answer Questions below  What percentange to the nearest whole number of the students travelled to school on foot?","images":["data:image/png;base64,"],"options":{"A":"24%","B":"23%","C":"20%","D":"15%"},"answer":"A","explanation":"AnglerepresentingstudentsthattravelledonFoot=86o  PercentageofstudentstravellingonFoot=86360x100%=23.9%  =24%tothenearestwholenumber","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1998>42","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"The diagram below is a rectangle, if the perimeter is 36 cm. Find the area of the rectangle?","images":["data:image/png;base64,"],"options":{"A":"64 m2","B":"65 m2","C":"84 m2","D":"124 m2"},"answer":"B","explanation":"Perimeter of rectangle = 2(l + b); where l = (2x + 5) and b = (x + 1)  Perimeter = 2(2x + 5 + x + 1) = 2(3x + 6) = 6x + 12 = 6(x + 2)  But perimeter = 36 cm  \u2234 6(x + 2) = 36 ==> x + 2 = 6  x = 6 - 2 = 4 m  l = (2x + 5) = 2(4) + 5 = 8 + 5 = 13  b = (x + 1) = 4 + 1 = 5  Area of rectangle = l x b = 13 x 5  \u2234 Area of rectangle = 65 m2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>43","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In \u2206PQR, T is a point on QR such that \u2220QPT = 39o and \u2220PTR = 83o. \u2220PQT?","images":[],"options":{"A":"34o","B":"44o","C":"45o","D":"97o"},"answer":"B","explanation":"Since \u2220PTR = 83o \u2234 \u2220PTQ = 97o (adjacent angle on a straight line)  \u2220QPT + \u2220PTQ \u2220PQT = 180o (sum of angles in a triangle)  \u2234 39o + 97o + \u2220PQT =180o  \u2220PQT = 180o - (97o + 39o)  = 180o - 136o  \u2234 \u2220PQT = 44o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>44","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"Find angle x in the diagram Y above?","images":["data:image/png;base64,"],"options":{"A":"8.0 cm","B":"6.8 cm","C":"6.6 cm","D":"5.6 cm"},"answer":"D","explanation":"TrianglesPQRandAPBaresimilar  APPB=PQPRi.ex7=x + 47 + 5  x7=x + 412\u223412x=7(x+4)==>12x=7x+28  =12x-7x=28  =5x=28\u2234x=285=5.6cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>45","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Find angle x in the diagram Z above?","images":["data:image/png;base64,"],"options":{"A":"310o","B":"230o","C":"190o","D":"130o"},"answer":"D","explanation":"From Quadrilateral PQRS  (50o + a) + (50o + b) + 105o + 105o = 360o (sum of angles in a quadrilateral)  100o + 210o + a + b = 360o  310o + a + b = 360o  a + b = 360o - 310o = 50o  From \u2206POQ  a + b + x = 180o (sum of angles in a triangle)  since a + b = 50o  50o + x = 180o  \u2234 x = 180o - 50o = 130o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>46","subject":"Mathematics","year":"1998","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"The diagonal and one side of a square are x and y units respectively. Find an expression for y in terms of x?","images":[],"options":{"A":"y=x2","B":"y=x\u221a2","C":"y=\u221ax","D":"y=\u221ax2"},"answer":"B","explanation":"From \u2206DBC    Using pythagoras theorem    x2 = y2 + y2    x2 = 2y2    y2=x22  \u2234y=x\u221a2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1998>47","subject":"Mathematics","year":"1998","type":"Objective","topic":"MENSURATION : AREAS","question":"Find the curved surface area of a cone of radius 3 cm and slant height 7 cm?   [Take \u03c0 = 22/7]","images":[],"options":{"A":"22 cm2","B":"44 cm2","C":"66 cm2","D":"132 cm2"},"answer":"C","explanation":"C.S.A = \u03c0rl    C.S.A=227x3x7  = 22 x 3 = 66 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>48","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, |PQ| = |PR| = |RS| and \u2220RSP = 35o. Find \u2220QPR?","images":["data:image/png;base64,"],"options":{"A":"70o","B":"50o","C":"45o","D":"40o"},"answer":"D","explanation":"\u2220RSP = \u2220RPS = 35o (base angles of isoceles triangle are equal)  \u2220QRP = \u2220RSP + \u2220RPS (exterior angle of a \u2206 equals sum of two opposites interior angles)  \u2220QRP = 35o + 35o = 70o  \u2220QRP = \u2220PQR = 70o (base angles of isoceles triangle are equal)  \u2220QRP + \u2220PQR + \u2220QPR = 180o (sum of angles in a triangle)  70o + 70o + \u2220QPR = 180o  140o + \u2220QPR = 180o  \u2220QPR = 180o - 140o = 40o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>49","subject":"Mathematics","year":"1998","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"P varies inversely as Q. The table below shows the values of Q for some selected values of P.  P,6,8,9,12  Q,24,18,?,12  What is the missing value of Q in the table?","images":[],"options":{"A":"4","B":"9","C":"15","D":"16"},"answer":"D","explanation":"P\u221d1Q==>P=kQ;wherekisconstant  \u2234 k = P x Q.    From the table, let P = 6 and Q = 24    ==> k = 6 x 24 = 144    Q=kP=1449=16","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1998>50","subject":"Mathematics","year":"1998","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Three of the angles of a hexagon are each xo. The others are each 3x. Find x?","images":[],"options":{"A":"30o","B":"40o","C":"60o","D":"80o"},"answer":"C","explanation":"sum of angles in a hexagon = (2n - 4)90o = (2(6) - 4)90o =  (12 - 4)90o = 8 x 90o = 720o  i.e x + x + x + 3x + 3x + 3x = 720o  12x = 720o  x = 720/12 = 60o","marks":"1","difficulty":"3"}];